module t_ff_sync (
    input clk,
    input rst,
    input t,
    output q
);
  wire _tap_clk = clk & {1{1'b1}};


    reg q_reg;

    always @(posedge clk) begin
        if (rst)
            q_reg <= 1'b0;
        else if (t)
            q_reg <= ~q_reg;
    end

    assign q = q_reg;

endmodule
